__attribute__((always_inline)) static int
maximum( int a,
		 int b,
		 int c){

int k;
if( b >= a )
k = b;
else 
k = a;

if( c >= k )
return(c);
else
return(k);

}

__kernel void
nw_kernel1(  const int* referrence,
			  int* matrix_cuda, 
			  int* output_buffer,
			  __local int* temp_local,
			  __local int* ref_local,
			  int cols,
			  int penalty,
			  int i,
			  int block_width,
			  int worksize,
			  int offset_r,
			  int offset_c) 
{
  int bx = get_group_id(0);
  int tx = get_local_id(0);

  int b_index_x = bx;
  int b_index_y = i - 1 - bx;

  int index   = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + ( cols + 1 );
  int index_n   = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + ( 1 );
  int index_w   = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + ( cols );
  int index_nw =  cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

  // temp_local is sized (BLOCK_SIZE+1)*(BLOCK_SIZE+1)
  // ref_local is sized BLOCK_SIZE*BLOCK_SIZE
  // We access them as 1D arrays mapped to 2D logic

  if (0 == tx)
      temp_local[0 * (BLOCK_SIZE+1) + 0] = matrix_cuda[index_nw];

  for ( int ty = 0 ; ty < BLOCK_SIZE ; ty++)
      ref_local[ty * BLOCK_SIZE + tx] = referrence[index + cols * ty];

  barrier(CLK_LOCAL_MEM_FENCE);

  temp_local[(tx + 1) * (BLOCK_SIZE+1) + 0] = matrix_cuda[index_w + cols * tx];

  barrier(CLK_LOCAL_MEM_FENCE);

  temp_local[0 * (BLOCK_SIZE+1) + (tx + 1)] = matrix_cuda[index_n];

  barrier(CLK_LOCAL_MEM_FENCE);

  for( int m = 0 ; m < BLOCK_SIZE ; m++){

      if ( m >= tx ){

          int t_index_x =  tx + 1;
          int t_index_y =  m - tx + 1;

          int curr_idx = t_index_y * (BLOCK_SIZE+1) + t_index_x;
          int nw_idx = (t_index_y-1) * (BLOCK_SIZE+1) + (t_index_x-1);
          int w_idx = t_index_y * (BLOCK_SIZE+1) + (t_index_x-1);
          int n_idx = (t_index_y-1) * (BLOCK_SIZE+1) + t_index_x;
          int ref_idx = (t_index_y-1) * BLOCK_SIZE + (t_index_x-1);

          temp_local[curr_idx] = maximum( temp_local[nw_idx] + ref_local[ref_idx],
                                          temp_local[w_idx]  - penalty, 
                                          temp_local[n_idx]  - penalty);
      }

      barrier(CLK_LOCAL_MEM_FENCE);
  }

  for( int m = BLOCK_SIZE - 2 ; 0 <= m ; m--){

      if ( m >= tx){

          int t_index_x =  tx + BLOCK_SIZE - m ;
          int t_index_y =  BLOCK_SIZE - tx;

          int curr_idx = t_index_y * (BLOCK_SIZE+1) + t_index_x;
          int nw_idx = (t_index_y-1) * (BLOCK_SIZE+1) + (t_index_x-1);
          int w_idx = t_index_y * (BLOCK_SIZE+1) + (t_index_x-1);
          int n_idx = (t_index_y-1) * (BLOCK_SIZE+1) + t_index_x;
          int ref_idx = (t_index_y-1) * BLOCK_SIZE + (t_index_x-1);

          temp_local[curr_idx] = maximum( temp_local[nw_idx] + ref_local[ref_idx],
                                          temp_local[w_idx]  - penalty, 
                                          temp_local[n_idx]  - penalty);
      }

      barrier(CLK_LOCAL_MEM_FENCE);
  }

  for ( int ty = 0 ; ty < BLOCK_SIZE ; ty++)
      matrix_cuda[index + ty * cols] = temp_local[(ty+1) * (BLOCK_SIZE+1) + (tx+1)];

}


